var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"RIFLE_CHARADE_NULL_C","text":{"KOREA":"큭……!? 젠장!!","JPN":"くっ……！？　くそ！！","ENG":"Kghk...! Crap!","TWN":"咳……！？該死！！"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"RIFLE_CHARADE_NULL_C","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"노엘 선수! 한 명 더 격추!","JPN":"ノエル選手！　また一人撃墜！","ENG":"Noelle shoots another one down!","TWN":"洛艾兒選手！又擊落一個！"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"스나이퍼란 간판이랑 안 어울린단 평가를 의식한 거야? 연이어 저격에 성공!","JPN":"スナイパーとしての看板に似合わないという評価を意識してるのかな？　続けて狙撃に成功！","ENG":"Was she bothered by people saying she was \\"not so sniper-like\\"? There, and she strikes again!","TWN":"是因為在意別人說她不適合當狙擊手的評價嗎？接連狙擊成功！"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"됐어. 이제 머릿수로도 안 밀리겠구만.","JPN":"よし。これなら、頭数でも不利じゃない。","ENG":"Good. We're even in numbers now.","TWN":"好欸！那現在大家人數都差不多。"},"stage":{"bg":"BASEMENT","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L8_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"역습이라도 할까? 저 자식들을 제대로 밟아 줘야지.","JPN":"逆襲でもする？　あいつらを確実に踏み潰してやらなきゃ。","ENG":"What do you say, should we fight back? We gotta trample those bastards.","TWN":"要反擊嗎？狠狠痛扁那些傢伙吧！"},"stage":{"bg":"BASEMENT","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"역습…….","JPN":"逆襲……","ENG":"Fighting back...","TWN":"反擊……"},"stage":{"bg":"BASEMENT","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"코치는 어떻게 생각하세요?","JPN":"コーチはどう思いますか？","ENG":"What do you think, Coach?","TWN":"教練怎麼說？"},"stage":{"bg":"BASEMENT","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>관객들에게 깊은 인상을 남겨 주면 어떤가?</color>","JPN":"<color=#ffd34c>観客たちに深い印象を残してあげるのはどうだ？</color>","ENG":"<color=#ffd34c>What about leaving a strong impression on the audience instead?</color>","TWN":"<color=#ffd34c>那就給觀眾留下一個深刻的印象吧？</color>"},"stage":{"bg":"BASEMENT","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"……역시 그렇죠?","JPN":"……やっぱりそうですよね？","ENG":"...You think so too, right?","TWN":"……教練也這麼認為嗎？"},"stage":{"bg":"BASEMENT","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"라이카, 방패 뒤로 와요. 칼에 찔린 상처 봐 줄게요.","JPN":"ライカ、盾の後ろに来て。刺された怪我を見てあげるわ。","ENG":"Laika, get behind the shield. I'll tend to your wounds.","TWN":"萊卡，來盾牌後面。我幫你看看刀傷。"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"너 왜 그래? 아까 암전됐을 때 다른 애로 바꿔치기 당했냐?","JPN":"あんた、どうした？　さっき暗転したとき、別人に入れ替えられたのか？","ENG":"What's wrong with you? Did they swap you with a different kid while the lights were out?","TWN":"你哪位？剛才夜戰時被人給掉包啦？"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"지시에 따르는 거예요.","JPN":"指示に従ってるの。","ENG":"I'm following orders.","TWN":"我只是聽從指示而已。"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"다 이겼다고 설치는 건 프로답지 못한 짓이니까요.","JPN":"ほぼ勝利したからって出しゃばるのは、プロらしくないことでしょ。","ENG":"Boasting victory isn't really professional.","TWN":"因為勝券在握就得意忘形，這種態度很不專業。"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"저희가 풋내기가 아니라는 걸 모두에게 보여 줄 거예요.","JPN":"私たちが初心者じゃないってことを、みんなに見せてあげるわ。","ENG":"We're going to show everyone that we're not just a bunch of rugrats.","TWN":"我要讓大家知道，我們才不是什麼菜鳥！"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"제한 시간은 점점 다가오는데─! 오빠들, 이대로 주저앉을 거야?","JPN":"そろそろ制限時間が終わりそうだけど―！　お兄さんたち、このまま崩れ落ちてしまうのか？","ENG":"The clock is ticking...! Have you given up, boys?","TWN":"時間不多囉—！帥哥們還不趕快振作起來嗎？"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"반면에 카나리아 스쿼드! 우세를 확신했는지 거점을 봉쇄했다!","JPN":"一方、カナリア・スクワッド！　優勢を確信したのか、拠点を封鎖！","ENG":"On the other hand, Canary Squad! They seem sure of their victory! There they go, barricading their base!","TWN":"再看看金絲雀小隊！是因為現在掌握優勢嗎？她們封鎖了據點！"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"퍼포먼스는? 개인기는? 뽐내고 싶은 게 잔뜩일 텐데~","JPN":"パフォーマンスは？　得意技は？　自慢したいことが山ほどあるはずなのに～","ENG":"Any performances? What about a trick or two? You can show off as much as you please!","TWN":"表演呢？個人秀呢？應該有很多想炫耀的吧～"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}}]`);export{e as default};